import './OverflowCount.scss';

import { createChilds } from ':components/Select/components/helper';
import { classNames } from ':helpers/classnames';
import type { JSX, MutableRefObject } from 'react';
import React, { type RefObject, useEffect, useRef } from 'react';

interface OverflowCountProps<T> {
	values: T[];
	inputRef: RefObject<HTMLInputElement | HTMLButtonElement | HTMLDivElement>;
	hiddenRef: MutableRefObject<HTMLParagraphElement>;
	countRef: MutableRefObject<HTMLParagraphElement>;
	className?: string;
}

export const OverflowCount = <T,>({
	inputRef,
	values,
	hiddenRef,
	countRef,
	className,
}: OverflowCountProps<T>): React.JSX.Element | null => {
	const canvasRef = useRef<HTMLCanvasElement>(null);
	const originalPaddingRef = useRef<number | null>(null);

	const hiddenChildren = createChilds(values);

	// Функция для пересчета padding-right
	const recalculatePadding = () => {
		if (!canvasRef.current || !hiddenRef.current || !inputRef.current || !countRef.current) {
			return;
		}

		const ctx = canvasRef.current.getContext('2d');
		if (!ctx) {
			return;
		}

		const el = globalThis.getComputedStyle(inputRef.current, null);
		const font = el.getPropertyValue('font');
		const lh = el.getPropertyValue('line-height');

		// Сохраняем изначальный padding-right только один раз
		if (originalPaddingRef.current === null) {
			const pr = el.getPropertyValue('padding-right');
			originalPaddingRef.current = +pr.slice(0, -2) || 16;
		}

		hiddenRef.current.style.font = font;

		// Используем реальную ширину элемента счетчика вместо canvas.measureText
		const counterRect = countRef.current.getBoundingClientRect();
		const counterWidth = counterRect.width || 0;

		const basePadding = originalPaddingRef.current;
		// Добавляем небольшой отступ (4px) чтобы троеточие не наезжало на счетчик
		const res = `${counterWidth + basePadding + 4}px`;
		inputRef.current.style.paddingRight = res;

		const counter = countRef.current;
		counter.style.lineHeight = lh;
		counter.style.right = `${6 + basePadding}px`;
	};

	// Первоначальная настройка и пересчет при изменении values
	useEffect(() => {
		recalculatePadding();
	}, [values, hiddenChildren]);

	// Дополнительный useEffect для отслеживания изменений текста счетчика
	useEffect(() => {
		if (!countRef.current) {
			return;
		}

		// Создаем MutationObserver для отслеживания изменений текста счетчика
		const observer = new MutationObserver(() => {
			// Небольшая задержка для того, чтобы DOM успел обновиться
			setTimeout(recalculatePadding, 0);
		});

		observer.observe(countRef.current, {
			childList: true,
			subtree: true,
			characterData: true,
		});

		return () => {
			observer.disconnect();
		};
	}, []);

	// Сброс padding при размонтировании
	useEffect(() => {
		return () => {
			if (inputRef.current && originalPaddingRef.current !== null) {
				inputRef.current.style.paddingRight = `${originalPaddingRef.current}px`;
			}
		};
	}, []);

	return (
		<>
			<p className={classNames('dsb__overflow__hidden dsb__overflow__text', className)} ref={hiddenRef}>
				{hiddenChildren}
			</p>
			<canvas ref={canvasRef} className="dsb__overflow__hidden" />
		</>
	);
};
